import { NextRequest, NextResponse } from 'next/server';
import OpenAI from 'openai';
import { SYSTEM_PROMPT, GENERATION_PROMPT, INITIAL_QUESTIONS } from '@/lib/logo-generator/prompts';
import { getAuthUser, verifyProjectOwnership, handleAuthError } from '@/lib/auth-helpers';

const openai = new OpenAI({
    apiKey: process.env.OPENAI_API_KEY,
});

export async function POST(request: NextRequest) {
    try {
        const formData = await request.formData();
        const projectId = formData.get('projectId') as string;
        const text = formData.get('text') as string;
        const voiceTranscript = formData.get('voiceTranscript') as string | null;
        const linksJson = formData.get('links') as string;
        const links = linksJson ? JSON.parse(linksJson) : [];

        if (!projectId) {
            return NextResponse.json({ error: 'projectId required' }, { status: 400 })
        }

        // Verify authentication and project ownership
        const user = await getAuthUser()
        await verifyProjectOwnership(projectId, user.id)

        // TODO: Process uploaded images with vision API if needed
        // const images = formData.getAll('images') as File[];

        // Generate conversation ID linked to project
        const conversationId = `conv_${projectId}_${Date.now()}_${Math.random().toString(36).substring(7)}`;

        // Call OpenAI to generate logo
        const completion = await openai.chat.completions.create({
            model: 'gpt-4o',
            messages: [
                {
                    role: 'system',
                    content: SYSTEM_PROMPT,
                },
                {
                    role: 'user',
                    content: GENERATION_PROMPT({
                        text,
                        voiceTranscript: voiceTranscript || undefined,
                        links: links.length > 0 ? links : undefined,
                    }),
                },
            ],
            response_format: { type: 'json_object' },
            temperature: 0.8,
        });

        const response = JSON.parse(completion.choices[0].message.content || '{}');

        // TODO: Store conversation in database linked to project
        // For now, we'll return the initial state
        const initialMessage = {
            role: 'assistant' as const,
            content: response.rationale || 'Voici votre logo initial. Répondez aux questions pour l\'affiner.',
            options: INITIAL_QUESTIONS[0].options,
        };

        return NextResponse.json({
            conversationId,
            svg: response.svg,
            messages: [initialMessage],
        });
    } catch (error) {
        return handleAuthError(error)
    }
}

