let userMessage = text;
if (voiceTranscript) {
    userMessage += `\n\nVoice transcript: ${voiceTranscript}`;
}
if (links.length > 0) {
    userMessage += `\n\nReference links: ${links.join(', ')}`;
}

// Call OpenAI to generate logo
const completion = await openai.chat.completions.create({
    model: 'gpt-4o',
    messages: [
        {
            role: 'system',
            content: SYSTEM_PROMPT,
        },
        {
            role: 'user',
            content: GENERATION_PROMPT({
                text,
                voiceTranscript: voiceTranscript || undefined,
                links: links.length > 0 ? links : undefined,
            }),
        },
    ],
    response_format: { type: 'json_object' },
    temperature: 0.8,
});

const response = JSON.parse(completion.choices[0].message.content || '{}');
const assistantContent = response.rationale || 'Voici votre logo initial. Répondez aux questions pour l\'affiner.';

// Store conversation and messages in database
const conversationId = nanoid();

await prisma.$transaction(async (tx) => {
    // Create conversation
    await tx.conversations.create({
        data: {
            id: conversationId,
            project_id: projectId,
            expert_type: 'CREATIVE_THINKING', // Logo generation is creative work
            status: 'ACTIVE',
            summary: `Logo generation: ${text.substring(0, 50)}...`,
            generated_cards: 0,
            updated_at: new Date(),
        },
    });

    // Store user message
    await tx.messages.create({
        data: {
            id: nanoid(),
            conversation_id: conversationId,
            role: 'USER',
            content: userMessage,
            model: 'gpt-4o',
            created_at: new Date(),
        },
    });

    // Store assistant response with SVG in metadata
    await tx.messages.create({
        data: {
            id: nanoid(),
            conversation_id: conversationId,
            role: 'ASSISTANT',
            content: assistantContent,
            generated_cards: [{ svg: response.svg, options: INITIAL_QUESTIONS[0].options }],
            model: 'gpt-4o',
            created_at: new Date(),
        },
    });
});

return NextResponse.json({
    conversationId,
    svg: response.svg,
    messages: [{
        role: 'assistant',
        content: assistantContent,
        options: INITIAL_QUESTIONS[0].options,
    }],
});

