import { NextRequest, NextResponse } from 'next/server';
import OpenAI from 'openai';
import { SYSTEM_PROMPT } from '@/lib/logo-generator/prompts';
import { getAuthUser, verifyProjectOwnership, handleAuthError } from '@/lib/auth-helpers';
import { prisma } from '@/lib/prisma';
import { nanoid } from 'nanoid';

const openai = new OpenAI({
    apiKey: process.env.OPENAI_API_KEY,
});

export async function POST(request: NextRequest) {
    try {
        const formData = await request.formData();
        const projectId = formData.get('projectId') as string;
        const conversationId = formData.get('conversationId') as string;
        const message = formData.get('message') as string;
        const linksJson = formData.get('links') as string;
        const links = linksJson ? JSON.parse(linksJson) : [];

        if (!projectId) {
            return NextResponse.json({ error: 'projectId required' }, { status: 400 })
        }

        if (!conversationId) {
            return NextResponse.json({ error: 'conversationId required' }, { status: 400 })
        }

        // Verify authentication and project ownership
        const user = await getAuthUser()
        await verifyProjectOwnership(projectId, user.id)

        // Build user message
        let userContent = message;
        if (links.length > 0) {
            userContent += `\n\nLiens de référence: ${links.join(', ')}`;
        }

        // Get conversation history from database
        const messages = await prisma.messages.findMany({
            where: { conversation_id: conversationId },
            orderBy: { created_at: 'asc' },
            select: {
                role: true,
                content: true,
            },
        });

        if (messages.length === 0) {
            return NextResponse.json({ error: 'Conversation not found' }, { status: 404 })
        }

        // Build history for OpenAI
        const history = messages.map((msg) => ({
            role: msg.role.toLowerCase() as 'user' | 'assistant',
            content: msg.content,
        }));

        // Determine if we should generate a logo or ask questions
        const shouldGenerateLogo = history.length === 1; // First user message after initial generation

        let systemMessage = SYSTEM_PROMPT;
        if (shouldGenerateLogo) {
            systemMessage += `\n\nGenerate a logo based on the user's description. Return a JSON object with:
{
  "logoHtml": "<svg>...</svg>",
  "message": "Brief explanation of the design",
  "options": ["Style option 1", "Style option 2", "Style option 3", "Style option 4"]
}

The SVG should be complete, valid, and visually appealing. Use modern design principles.`;
        } else {
            systemMessage += `\n\nContinue the conversation naturally. If appropriate, ask clarifying questions with 3-4 options. Return JSON:
{
  "message": "Your response",
  "options": ["Option 1", "Option 2", "Option 3"] // optional
}`;
        }

        // Call OpenAI
        const completion = await openai.chat.completions.create({
            model: 'gpt-4o',
            messages: [
                {
                    role: 'system',
                    content: systemMessage,
                },
                ...history,
                {
                    role: 'user',
                    content: userContent,
                },
            ],
            response_format: { type: 'json_object' },
            temperature: 0.8,
        });

        const response = JSON.parse(completion.choices[0].message.content || '{}');

        // Store new messages in database
        await prisma.$transaction(async (tx) => {
            // Store user message
            await tx.messages.create({
                data: {
                    id: nanoid(),
                    conversation_id: conversationId,
                    role: 'USER',
                    content: userContent,
                    model: 'gpt-4o',
                    created_at: new Date(),
                },
            });

            // Store assistant response
            await tx.messages.create({
                data: {
                    id: nanoid(),
                    conversation_id: conversationId,
                    role: 'ASSISTANT',
                    content: response.message,
                    generated_cards: response.logoHtml ? [{ logoHtml: response.logoHtml, options: response.options }] : [],
                    model: 'gpt-4o',
                    created_at: new Date(),
                },
            });

            // Update conversation timestamp
            await tx.conversations.update({
                where: { id: conversationId },
                data: { updated_at: new Date() },
            });
        });

        return NextResponse.json({
            message: response.message,
            options: response.options,
            logoHtml: response.logoHtml,
        });
    } catch (error) {
        return handleAuthError(error)
    }
}

