export async function GET(
    request: NextRequest,
    { params }: { params: Promise<{ id: string }> }
) {
    const { id } = await params;
    try {
        const conversationId = id;

        // Extract projectId from conversationId (format: conv_{projectId}_{timestamp}_{random})
        const projectId = conversationId.split('_')[1];

        if (!projectId) {
            return NextResponse.json({ error: 'Invalid conversationId format' }, { status: 400 })
        }

        // Verify authentication and project ownership
        const user = await getAuthUser()
        await verifyProjectOwnership(projectId, user.id)

