import { NextRequest, NextResponse } from 'next/server';
import { getAuthUser, verifyProjectOwnership, handleAuthError } from '@/lib/auth-helpers';
import { prisma } from '@/lib/prisma';

export async function GET(
    request: NextRequest,
    { params }: { params: Promise<{ id: string }> }
) {
    const { id } = await params;
    try {
        const conversationId = id;

        // Get conversation to extract projectId for ownership verification
        const conversation = await prisma.conversations.findUnique({
            where: { id: conversationId },
            select: {
                project_id: true,
            },
        });

        if (!conversation) {
            return NextResponse.json({ error: 'Conversation not found' }, { status: 404 })
        }

        // Verify authentication and project ownership
        const user = await getAuthUser()
        await verifyProjectOwnership(conversation.project_id, user.id)

        // Fetch messages from database
        const messages = await prisma.messages.findMany({
            where: { conversation_id: conversationId },
            orderBy: { created_at: 'asc' },
            select: {
                role: true,
                content: true,
            },
        });

        return NextResponse.json({
            messages: messages.map((msg) => ({
                role: msg.role.toLowerCase(),
                content: msg.content,
            })),
        });
    } catch (error) {
        return handleAuthError(error)
    }
}

